def _merge_yao_observations(gua_name: str, auto: dict[int, str]) -> dict[int, str]:
    manual = _YAO_MANUAL.get(gua_name, {})
    merged = dict(auto)
    for k, v in manual.items():
        merged[k] = v
    return merged


def tongyun_gua_xiang(gua_name: str) -> dict | None:
    """卷十三：單卦觀象全文。"""
    data = _GUA_XIANG.get(gua_name)
    if not data:
        return None
    out = dict(data)
    if gua_name in _GUA_SUPPLEMENT:
        out.update(_GUA_SUPPLEMENT[gua_name])
    out["運"] = _GUA_YUN.get(gua_name, data.get("運", ""))
    auto = _split_yao_observations(out.get("總述", ""))
    out["爻觀象"] = _merge_yao_observations(gua_name, auto)
    return out


def _split_yao_observations(zongshu: str) -> dict[int, str]:
    if not zongshu:
        return {}
    result = {}
    for idx, keys in _YAO_PATTERNS:
        parts = []
        for k in keys:
            pos = 0
            while True:
                i = zongshu.find(k, pos)
                if i < 0:
                    break
                snippet = zongshu[i : i + 72].rstrip("，。；")
                if snippet not in parts:
                    parts.append(snippet)
                pos = i + len(k)
        if parts:
            result[idx] = "；".join(parts[:2])
    return result


def tongyun_gua_xiang_for_year(year: int) -> dict:
    rugua = config.tongyun_rugua(year)
    gua = tongyun_gua_xiang(rugua["卦"])
    if not gua:
        return {
            "公元年": year,
            "卦": rugua["卦"],
            "運": rugua["運"],
            "爻": rugua["爻名"],
            "觀象": None,
        }
    yao_obs = gua.get("爻觀象", {}).get(rugua["爻"], "")
    return {
        "公元年": year,
        "運": rugua["運"],
        "卦": rugua["卦"],
        "爻": rugua["爻"],
        "爻名": rugua["爻名"],
        "經年": gua.get("經年"),
        "象曰": gua.get("象曰", ""),
        "總述": gua.get("總述", ""),
        "當前爻觀象": yao_obs,
        "運總論": _YUN_INTRO.get(gua.get("運", ""), ""),
    }


def zonghe(year: int) -> dict:
    info = tongyun_gua_xiang_for_year(year)
    gua = info.get("卦")
    full = tongyun_gua_xiang(gua) if gua else None
    xiang = info.get("象曰", "")
    tip = (
        f"統十二運卦象：當前{info.get('運')}之{info.get('卦')}{info.get('爻名', '')}"
        + (f"；{xiang[:36]}…" if xiang else "")
    )
    return {
        "統運卦象": info,
        "卦象全文": full,
        "要訣": tip,
    }
